SELECT AVG(prcp) 
FROM weather_data 
WHERE station_id = '0';

SELECT station_id, COUNT(*) AS record_count
FROM weather_data
GROUP BY station_id;

SELECT COUNT(*) AS total_records
FROM weather_data
WHERE station_id = '0' AND date = '2023-10-01';

SELECT SUM(prcp) AS total_precipitation
FROM weather_data
WHERE date = '2023-10-05' AND time = '12:00:00';

SELECT AVG(tmax) AS avg_temp
FROM weather_data
WHERE station_id = '0' AND date BETWEEN '2023-01-01' AND '2023-10-01';

SELECT MIN(prcp) AS min_precipitation
FROM weather_data
WHERE date LIKE '2023-01-%' AND station_id = '0';

SELECT date, tmax
FROM weather_data
WHERE station_id = '0' AND date = '2023-10-04';
